// Filter to live-capable enabled RSS sources only.
// Business logic stays in the API — this node only filters.
const sources = $input.first().json.sources || [];
const liveEnabled = $input.first().json.liveIntakeEnabled;
if (!liveEnabled) {
  console.log('Live intake kill switch is OFF — skipping all sources.');
  return [];
}
const rss = sources.filter(s => s.type === 'rss' && s.enabled && s.liveCapable);
return rss.map(s => ({ json: s }));
